#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int *arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        long long ans = 0;
        int cnt[3] = {0, 0, 0};
        int r = 0;
        for (int l = 0; l < n; ++l) {
            while (r < n && (cnt[0] == 0 || cnt[1] == 0 || cnt[2] == 0)) {
                cnt[arr[r]]++;
                ++r;
            }
            if (cnt[0] && cnt[1] && cnt[2]) {
                ans += (long long)(n - r + 1);
            }
            cnt[arr[l]]--;
        }
        printf("%lld\n", ans);
        free(arr);
    }
    return 0;
}

